mapper.update:
update biz_account
set balance=#{balance}, frozen_amount=#{frozenAmount}, total_recharge=#{totalRecharge}, total_consume=#{totalConsume}, status=#{status}, update_time=#{updateTime}
where id=#{id}

update biz_account
set balance = balance + #{amount}, total_recharge = ifnull(total_recharge, 0) + #{amount}, update_time = #{updateTime}
where id = #{accountId}

update biz_account
set balance = balance - #{amount}, total_consume = ifnull(total_consume, 0) + #{amount}, update_time = #{updateTime}
where id = #{accountId} and balance >= #{amount}

update biz_account
set balance = balance + #{amount}, update_time = #{updateTime}
where id = #{accountId}


update biz_account
set frozen_amount = ifnull(frozen_amount, 0) + #{amount}, update_time = #{updateTime}
where id = #{accountId} and (balance - ifnull(frozen_amount, 0)) >= #{amount}

update biz_account
set frozen_amount = frozen_amount - #{amount}, update_time = #{updateTime}
where id = #{accountId} and frozen_amount >= #{amount}


update biz_account
set balance = balance - #{finalAmount},
    frozen_amount = frozen_amount - #{frozenAmount},
    total_consume = ifnull(total_consume, 0) + #{finalAmount},
    update_time = #{updateTime}
where id = #{accountId}
  and frozen_amount >= #{frozenAmount}
  and (balance - ifnull(frozen_amount, 0) + #{frozenAmount}) >= #{finalAmount}
